    """Count the number of cheap pairs in the given array."""
    count = 0
    A.sort()  # Sort the array to use two-pointer technique

    for i in range(N):
        for j in range(i + 1, N):
            if A[i] + A[j] <= T:
                count += 1
            else:
                break  # If the sum exceeds T, break the inner loop

    return count

